package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetHeaderCommentsReturnsCloneWhenNotNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to set private headerComments field to a non-null value
        Field headerCommentsField = CSVFormat.class.getDeclaredField("headerComments");
        headerCommentsField.setAccessible(true);
        String[] comments = new String[] {"comment1", "comment2"};
        headerCommentsField.set(format, comments);

        String[] result = format.getHeaderComments();

        assertNotNull(result);
        assertArrayEquals(comments, result);
        // Ensure returned array is a clone, not the original reference
        assertNotSame(comments, result);
    }

    @Test
    void testGetHeaderCommentsReturnsNullWhenNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to set private headerComments field to null
        Field headerCommentsField = CSVFormat.class.getDeclaredField("headerComments");
        headerCommentsField.setAccessible(true);
        headerCommentsField.set(format, null);

        String[] result = format.getHeaderComments();

        assertNull(result);
    }
}
